    {
      "n": 11,
      "column": "left",
      "text": "Wiꞥſch feen jawu jaunu\nEhſeli pee ta Wihna - Kohka / un\nawas Eheſta-Mahtes Kummetu\npee tahm krahfnahm Wihnu-\nStihgahm. Wiꞥſch jawas Drehs-\nes eekſch Wihna masgahs / un\nawu Mehteli eekſch Wihna-Kek-\ngarn Affini/\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Winna Azziſ irr jo farka-\nnas / ne ka Wihns/ un winna\nSohbi irr baltaki/ ne ka Veens.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Sebulans dsihwohs pee\nInhras Obstahm / un tas buhs\npee peelaſchamahm Laiwo Wee-\nahm / un aistiks lihds Siḣ-\nonai.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Ihsascharis irr weens stip-\nis faulains Ehſelis / un gulſehs\ntarp diwi Eschahm.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Rad wiꞥſch to Duffescha-\nnu redseja/ ka ta labba bija/ un to\nSetmmi / ka ta janfa bija / tad\nlohzija wiꞥſch jawus Kamſchus\npee Nefchanas / un kalpoja Mes-\nlus dohdams.\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Dans teefahs jawus Lau-\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Dans buhs weena\nTschuhſchka Zelt-Malla/ weena\nOhdse Zellixu-Malla/ koḥsdami\nSirgam Papehſchoß / ka winna\nJahjeis atpakkat friht.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "KUNGS/es gaidu us ta-\nwu Pestischanu.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Gads / to weens Pułke-\nuswarrehs/ bet wiꞥſch pehz gall-\nuswarrehs.\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "No Ahsera/winna Mais-\nbuhs trekna / un wiꞥſch isdoḥ-\nKehniſkus Gardumus.\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Nawtalis irr weena pa-\nlaista Erſchku-Mahte / kas mih-\nligus Wahrdus dohd.\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Jahſeps irr weens anglige-\nSars / weens angligs Sars,\nAwota Matta/ tee Sarri tekt po-\nMuhro wirfin.\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Tee Strehlneekt irr win-\nnam Rubktumu padarrijfchi/ te-\nirr apſchaudijufchi / un winnu\neenihdeifschi.\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Bet winna Stohps ir-\nstipris palizzis / un winna Rohfu-\nElkoni irr stiprinati/zaur ta War-\nrena Rohkahm eekſch Jehkaba\nno winna irr tas Israeta * Gans-\nAfmings.\n"
    },
